class Solution {
public:
    int vowelStrings(vector<string>& words, int left, int right) {
        int count = 0;
        unordered_set<char> vowels = {'a', 'e', 'i', 'o', 'u'};
        for (int i = left; i <= right; i++) {
            string word = words[i];
            if (vowels.count(word[0]) && vowels.count(word[word.size() - 1])) {
                count++;
            }
        }
        return count;
    }
};
